for type_code, texts in replacements.items():
    pattern_解説 = r'(## vs \[' + type_code + r'\].*?### 相性解説\n\n).*?(?=\n\n### 一緒に楽しむコツ)'
    content = re.sub(pattern_解説, r'\g<1>' + texts["相性解説"], content, flags=re.DOTALL)
    
    pattern_コツ = r'(## vs \[' + type_code + r'\].*?### 一緒に楽しむコツ\n\n).*?(?=\n\n### 摩擦ポイント)'
    content = re.sub(pattern_コツ, r'\g<1>' + texts["一緒に楽しむコツ"], content, flags=re.DOTALL)
    
    pattern_摩擦 = r'(## vs \[' + type_code + r'\].*?### 摩擦ポイント\n\n).*?(?=\n\n### 目的の持ち方)'
    content = re.sub(pattern_摩擦, r'\g<1>' + texts["摩擦ポイント"], content, flags=re.DOTALL)

with open(file_path, 'w', encoding='utf-8') as f:
    f.write(content)

